previewCss:
.darma-loader-darma-custom-477 {--loader-bg: var(--loader-bg, #ffffff);
  --loader-secondary-color: var(--loader-secondary-color, #38bdf8);
   width: 60px;
   aspect-ratio: 1;
   display: flex;
   color: var(--loader-color, #2563eb);
   border: 4px solid;
   box-sizing: border-box;
   border-radius: 50%;
   background: radial-gradient(circle 5px, currentColor 95%,#0000), linear-gradient(currentColor 50%,#0000 0) 50%/4px 60% no-repeat;
   animation: darma-loader-darma-custom-477-l1 2s infinite linear;
}
.darma-loader-darma-custom-477:before  {
  content: "";
   flex: 1;
   background:linear-gradient(currentColor 50%,#0000 0) 50%/4px 80% no-repeat;
   animation: inherit;
}
@keyframes darma-loader-darma-custom-477-l1  {
  100% {transform: rotate(1turn)}
}

